              <div className="w-8 h-8 rounded-full border-2 border-white flex items-center justify-center text-[9px] font-bold" style={{ backgroundColor: isBgDark ? 'rgba(255,255,255,0.1)' : '#f0edea', color: mutedColor }}>+500</div>
