          <h3 className="text-[10px] md:text-sm font-black text-gray-900 uppercase tracking-tight truncate flex-1">{product.name}</h3>
          {product.price != null && <p className="text-[10px] md:text-sm font-black text-[var(--secondary)]">${product.price.toLocaleString('es-CO')}</p>}
        </div>
        <p className="text-[8px] md:text-[10px] text-gray-400 font-bold uppercase tracking-widest">{product.category}</p>
      </div>
    </button>
  );
}

function EditorialInfo({ brand, secondaryColor }: { brand: BrandData; secondaryColor?: string }) {
  const DAYS_ORDER = ['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado', 'Domingo'];
  let scheduleEntries: [string, string][] = [];
  try {
    const raw = brand.schedule ?? {};
    if (raw && typeof raw === 'object') {
      scheduleEntries = DAYS_ORDER.filter(d => raw[d] || raw[d.toLowerCase()]).map(d => [d, (raw[d] || raw[d.toLowerCase()]) as string]);
    }
  } catch(e) {}

  const theme = useContrastTheme('#ffffff');
  const accentColor = secondaryColor || '#FF5C3A';

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-8 w-full">
      {/* IZQUIERDA: Información */}
      <div className="p-6 md:p-10 rounded-[2rem] md:rounded-[3.5rem] border shadow-sm space-y-6 md:space-y-8" style={{ backgroundColor: theme.bg, borderColor: theme.border }}>
        <div className="flex items-center gap-4 border-b pb-6" style={{ borderColor: theme.border }}>
          <div className="w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center text-white shadow-xl" style={{ backgroundColor: brand.widget_bg_color || '#0a0a0a' }}>
            <MapPinIcon className="w-5 h-5 md:w-6 md:h-6" />
          </div>
          <div>
            <h4 className="text-[9px] md:text-xs font-black uppercase tracking-[0.3em]" style={{ color: accentColor }}>Ubicación</h4>
            <p className="text-xs md:text-sm font-black uppercase italic" style={{ color: theme.text }}>Presencia Física</p>
          </div>
        </div>
        <div className="space-y-6">
          {brand.city_display && (
            <p className="text-lg md:text-2xl font-black uppercase italic tracking-tighter leading-none" style={{ color: theme.text }}>{brand.city_display}</p>
          )}
          {brand.rating && (
            <div className="flex flex-col gap-2">
              <div className="flex gap-0.5 text-yellow-400">
                {[1,2,3,4,5].map(i => <StarIcon key={i} className="w-3.5 h-3.5 md:w-4 md:h-4" filled={i <= Math.round(brand.rating!)} />)}
              </div>
              <div className="flex items-baseline gap-2">
                <span className="text-2xl md:text-3xl font-black tracking-tighter" style={{ color: theme.text }}>{brand.rating.toFixed(1)}</span>
                <span className="text-[9px] md:text-[10px] font-black uppercase tracking-widest" style={{ color: theme.muted }}>/ {brand.total_reviews} reviews</span>
              </div>
            </div>
          )}
          {brand.national_shipping && (
            <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-lg text-[9px] md:text-[10px] font-black uppercase tracking-widest border" style={{ backgroundColor: theme.surface, color: theme.text, borderColor: theme.border }}>
              <span style={{ color: accentColor }}><TruckIcon className="w-3.5 h-3.5 md:w-4 md:h-4" /></span> Envíos Nacionales
            </div>
          )}
        </div>
      </div>

      {/* DERECHA: Horarios */}
      <div className="p-6 md:p-10 rounded-[2rem] md:rounded-[3.5rem] border shadow-sm space-y-6 md:space-y-8" style={{ backgroundColor: theme.bg, borderColor: theme.border }}>
        <div className="flex items-center gap-4 border-b pb-6" style={{ borderColor: theme.border }}>
          <div className="w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center text-white shadow-xl" style={{ backgroundColor: brand.widget_bg_color || '#0a0a0a' }}>
            <svg className="w-5 h-5 md:w-6 md:h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M12 8v4l3 3m6-3a9 9 0 11-12 0 9 9 0 0112 0z" /></svg>
          </div>
          <div>
            <h4 className="text-[9px] md:text-xs font-black uppercase tracking-[0.3em]" style={{ color: accentColor }}>Disponibilidad</h4>
            <p className="text-xs md:text-sm font-black uppercase italic" style={{ color: theme.text }}>Nuestros Horarios</p>
          </div>
        </div>
        <div className="space-y-2 md:space-y-3">
          {scheduleEntries.length > 0 ? (
            scheduleEntries.map(([d, h]) => (
              <div key={d} className="flex justify-between items-center text-[10px] md:text-xs border-b pb-2 last:border-0 last:pb-0" style={{ borderColor: theme.border }}>
                <span className="font-black uppercase tracking-widest" style={{ color: theme.muted }}>{d}</span>
                <span className={`font-black uppercase ${h.toLowerCase().includes('cerrado') ? 'text-red-500 italic' : ''}`} style={{ color: h.toLowerCase().includes('cerrado') ? undefined : theme.text }}>{h}</span>
              </div>
            ))
          ) : (
            <p className="text-[10px] md:text-xs italic font-medium uppercase tracking-widest" style={{ color: theme.muted }}>No hay horarios registrados.</p>
          )}
        </div>
      </div>
    </div>
  );
}

function EditorialAbout({ brand, primaryColor }: { brand: BrandData; primaryColor: string }) {
  const bgColor = brand.widget_bg_color || '#0a0a0a';
  const theme = useContrastTheme(bgColor);
  if (!brand.brand_description) return null;
  return (
    <section className="py-6 md:py-16">
      <div className="p-8 md:p-16 rounded-[2.5rem] md:rounded-[4rem] relative overflow-hidden shadow-2xl" style={{ backgroundColor: bgColor }}>
        <div className="absolute top-0 right-0 p-12 opacity-10">
          <SparklesIcon className="w-32 h-32 md:w-48 md:h-48" />
        </div>
        <div className="relative z-10 space-y-4 md:space-y-6 text-center md:text-left">
          <span className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.5em]" style={{ color: theme.muted }}>Nuestra Historia</span>
          <p className="text-base md:text-3xl leading-tight font-black italic uppercase tracking-tighter max-w-4xl" style={{ color: theme.text }}>
            &quot;{brand.brand_description}&quot;
          </p>
        </div>
      </div>
    </section>
  );
}

export function TemplateEditorial({ brandSlug, brand, products, footerUrl, isPreview = false }: { brandSlug: string; brand: BrandData; products: ProductData[]; footerUrl?: string; isPreview?: boolean }) {
  const primary = brand.social_links?._landing_primary || brand.primary_color || '#111111';
  const secondary = brand.social_links?._landing_secondary || primary;
  const [selectedId, setSelectedId] = useState<string | null>(products && products.length > 0 ? products[0].id : null);

  const socialLinks = brand.social_links || {};
  const entries = getVisibleSocialEntries(socialLinks);
  const socialIcons: Record<string, React.ReactNode> = {
    instagram: <InstagramIcon className="w-3.5 h-3.5" />,
    facebook:  <FacebookIcon  className="w-3.5 h-3.5" />,
    tiktok:    <TikTokIcon    className="w-3.5 h-3.5" />,
    youtube:   <YouTubeIcon   className="w-3.5 h-3.5" />,
    x:         <XIcon         className="w-3.5 h-3.5" />,
  };

  const handleProductClick = (id: string) => {
    setSelectedId(id);
    const el = document.getElementById('editorial-tryon');
    if (el) el.scrollIntoView({ behavior: 'smooth', block: 'center' });
  };

  return (
    <div className={`min-h-screen flex flex-col bg-[#fcfcfc] ${brand.landing_font || 'font-jakarta'} overflow-x-hidden ${isPreview ? 'p-0 h-auto' : ''}`} style={{ "--primary": primary, "--secondary": secondary, "--secondary-10": secondary + "1a", "--secondary-20": secondary + "33", "--secondary-05": secondary + "0d" } as React.CSSProperties}>
      <EditorialHeader brand={brand} entries={entries} socialIcons={socialIcons} />
      <EditorialHero brand={brand} />
      
      <main className="max-w-6xl mx-auto w-full px-4 md:px-6 py-12 md:py-20">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 md:gap-12 items-start mb-16">
          {/* Catálogo Prioritario */}
          <div className="order-2 lg:order-1">
            <div className="flex items-center justify-between border-b-2 border-black pb-4 mb-10">
              <h2 className="text-3xl font-black uppercase italic tracking-tighter">Colección</h2>
              <span className="text-[10px] font-black bg-black text-white px-3 py-1 uppercase">{products?.length || 0} Items</span>
            </div>
            
            <div className="grid grid-cols-2 xl:grid-cols-3 gap-6 md:gap-8">
              {products && Array.isArray(products) && products.map(p => (
                <EditorialProductCard key={p.id} product={p} selected={selectedId === p.id} primaryColor={primary} onClick={() => handleProductClick(p.id)} />
              ))}
            </div>
          </div>

          {/* Probador Prioritario (Sidebar Sticky) */}
          <aside className="order-1 lg:order-2">
            <div id="editorial-tryon" className="lg:sticky lg:top-28">
              <div className={isPreview ? "overflow-hidden bg-white" : "rounded-[3rem] overflow-hidden shadow-[0_40px_80px_-15px_rgba(0,0,0,0.15)] bg-white border border-gray-100"}>
                <div className="px-6 py-4 text-white flex justify-between items-center" style={{ backgroundColor: primary }}>
                  <span className="font-black text-[10px] uppercase tracking-widest flex items-center gap-2">
                    <SparklesIcon className="w-4 h-4" /> Probador IA
                  </span>
                  <span className="text-[8px] font-black opacity-60">AI POWERED</span>
                </div>
                <div className="bg-white">
                  <TryOnWidget brandSlug={brandSlug} isEmbed={true} initialProductId={selectedId} forceLayout="bare" lockProductSelection={true} />
                </div>
              </div>
              <p className="text-center mt-6 text-[9px] font-black uppercase tracking-[0.3em] text-gray-300">Desarrollado por Lookitry AI</p>
            </div>
          </aside>
        </div>

        {/* Información y Horarios */}
        <EditorialInfo brand={brand} secondaryColor={secondary} />

        {/* Descripción de marca */}
        <EditorialAbout brand={brand} primaryColor={primary} />
      </main>

      <footer 
        className="mt-20 py-20 px-6 text-center transition-colors duration-500" 
        style={{ backgroundColor: brand.widget_bg_color || '#0a0a0a', color: '#ffffff' }}
      >
        <div className="max-w-6xl mx-auto space-y-12">
          {/* Logo / Nombre en Footer */}
          <div className="flex flex-col items-center gap-4">
            {brand.logo ? (
              <img src={brand.logo_light || brand.logo} alt={brand.name} className="h-12 w-auto object-contain opacity-90 mb-2 grayscale brightness-200" />
            ) : (
              <div className="h-12 w-12 rounded-2xl flex items-center justify-center text-white font-black text-xl mb-2" style={{ backgroundColor: primary }}>
                {brand.name?.slice(0, 2).toUpperCase()}
              </div>
            )}
            <div className="w-12 h-1 bg-[var(--secondary)] rounded-full opacity-50" />
          </div>

          {/* Social Links en Footer */}
          {entries && entries.length > 0 && (
            <div className="flex flex-wrap items-center justify-center gap-4">
              {entries.map(([platform, url]) => (
                <a key={platform} href={url} target="_blank" rel="noopener noreferrer" aria-label={`Síguenos en ${platform}`} className="w-12 h-12 rounded-2xl bg-white/5 border border-white/10 flex items-center justify-center transition-all hover:bg-white hover:text-black hover:scale-110 active:scale-95 shadow-xl focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#FF5C3A] focus-visible:ring-offset-2">
                  {socialIcons[platform.toLowerCase()] ?? null}
                </a>
              ))}
            </div>
          )}

          {/* Copyright y Branding Lookitry */}
          <div className="pt-12 border-t border-white/5 space-y-6">
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-white/30">
              Transformando la experiencia de compra online
            </p>
            <div className="flex flex-col md:flex-row items-center justify-center gap-4 md:gap-8 text-[9px] font-black text-white/20 uppercase tracking-widest">
              <span>© 2026 {brand.name} </span>
              <span className="hidden md:block">|</span>
              <p>
                Powered by <a href={footerUrl || 'https://lookitry.com'} target="_blank" rel="noopener noreferrer" className="font-bold hover:opacity-80 transition-opacity text-white">Look<span className="text-[#FF5C3A]">itry</span> IA</a>
              </p>
            </div>
          </div>
        </div>
      </footer>

      {brand.whatsapp_contact && !isPreview && <WhatsAppFAB phone={brand.whatsapp_contact} message={brand.whatsapp_message} />}
    </div>
  );
}

'use client';

import { useState } from 'react';
import { TryOnWidget } from '@/components/tryon/TryOnWidget';
import { 
  BrandData, 
  ProductData, 
  WhatsAppFAB, 
  BrandLogo, 
  ProductImage, 
  ProductBadge, 
  CoverImage, 
  getCoverPresentation,
  getVisibleSocialEntries,
  isDarkColor,
  getSmartMutedColor,
  getSmartBorderColor,
  useContrastTheme,
  YouTubeIcon, 
  XIcon, 
  InstagramIcon, 
  FacebookIcon, 
  TikTokIcon,
  SparklesIcon
} from './shared';

// ── Sub-componentes ──────────────────────────────────────────────────────────

function ProbadorNav({ brand }: { brand: BrandData }) {
  const entries = getVisibleSocialEntries(brand.social_links || {});
  const socialIcons: Record<string, React.ReactNode> = {
    instagram: <InstagramIcon className="w-3.5 h-3.5" />,
    facebook:  <FacebookIcon  className="w-3.5 h-3.5" />,
    tiktok:    <TikTokIcon    className="w-3.5 h-3.5" />,
    youtube:   <YouTubeIcon   className="w-3.5 h-3.5" />,
    x:         <XIcon         className="w-3.5 h-3.5" />,
  };
  const primary = brand.social_links?._landing_primary || brand.primary_color || '#111111';
  const secondary = brand.social_links?._landing_secondary || primary;
  return (
    <nav className="sticky top-0 z-50 h-16 md:h-20 flex items-center justify-between px-4 md:px-8 gap-4 shadow-xl" 
      style={{ 
        backgroundColor: brand.header_color || '#000000', 
        borderBottom: '1px solid rgba(255,255,255,0.05)'
      }}>
      <div className="flex items-center gap-2 min-w-0 flex-1">
        <div className="shrink-0">
          {brand.logo && (
            <BrandLogo
              src={brand.logo_light || brand.logo}
              alt={brand.name}
              className="h-6 md:h-8 w-auto object-contain"
            />
          )}
        </div>
        {brand.show_brand_name !== false && (
          <span className="font-bold text-sm md:text-base text-white tracking-tight uppercase italic truncate">
            {brand.name}
          </span>
        )}
      </div>
      {entries.length > 0 && (
        <div className="flex gap-1.5 overflow-x-auto no-scrollbar py-1 shrink-0 max-w-[140px] sm:max-w-none justify-end">
          {entries.map(([platform, url]) => (
            <a key={platform} href={url} target="_blank" rel="noopener noreferrer" aria-label={`Síguenos en ${platform}`}
              className="w-7 h-7 rounded-lg border flex items-center justify-center transition-all hover:scale-110 shrink-0 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#FF5C3A] focus-visible:ring-offset-2"
              style={{ borderColor: 'rgba(255,255,255,0.15)', color: 'rgba(255,255,255,0.7)' }}>
              {socialIcons[platform.toLowerCase()] ?? null}
            </a>
          ))}
        </div>
      )}
    </nav>
  );
}

function ProbadorHero({ brand, onScrollDown, isPreview = false }: { brand: BrandData; onScrollDown: () => void; isPreview?: boolean }) {
  const primary = brand.social_links?._landing_primary || brand.primary_color || '#111111';
  const secondary = brand.social_links?._landing_secondary || primary;
  const hasCover = !!brand.cover_image_url;
  const { backgroundColor: heroBg, imageOpacity } = getCoverPresentation(brand, '#0f0f0f');
  return (
    <section className={`relative ${isPreview ? 'py-8 md:py-12' : 'py-16 md:py-24'} px-6 text-center overflow-hidden`} style={{ backgroundColor: heroBg }}>
      {hasCover && (
        <CoverImage src={brand.cover_image_url} alt={brand.name} className="absolute inset-0 w-full h-full object-cover" style={{ opacity: imageOpacity }} />
      )}
      <div className="relative z-10 max-w-2xl mx-auto text-white">
        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full border border-white/20 bg-white/5 backdrop-blur-md mb-6 md:mb-8">
          <span className="w-1.5 h-1.5 rounded-full animate-pulse" style={{ backgroundColor: primary }} />
          <span className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.2em]">IA Probador Activo</span>
        </div>
        <h1 className="text-3xl md:text-7xl font-black leading-[0.9] tracking-tighter mb-6 italic uppercase">
          {brand.name},<br />
          <em className="not-italic" style={{ color: primary }}>{brand.slogan || 'Moda Inteligente'}</em>
        </h1>
        {brand.brand_description && (
          <p className="text-sm md:text-base font-medium leading-relaxed mb-8 md:mb-10 max-w-lg mx-auto opacity-80">{brand.brand_description}</p>
        )}
        <button onClick={onScrollDown} className="inline-flex items-center gap-3 px-8 py-4 rounded-2xl text-xs md:text-sm font-black uppercase tracking-widest transition-all hover:scale-105 active:scale-95 shadow-2xl" style={{ backgroundColor: primary, color: '#fff' }}>
          Ver Colección
        </button>
      </div>
    </section>
  );
}

function ProbadorTrustBar({ brand }: { brand: BrandData }) {
  const rating = brand.rating ?? 4.9;
  const reviews = brand.total_reviews ?? 0;
  const items = [
    { value: rating.toFixed(1), label: 'rating' },
    { value: reviews > 0 ? `+${reviews}` : '96%', label: 'pruebas' },
    { value: '~12s', label: 'tiempo' },
    { value: 'IA', label: 'tech' },
  ];
  const theme = useContrastTheme('#ffffff');

  return (
    <div className="flex border-b overflow-x-auto no-scrollbar" style={{ backgroundColor: theme.bg, borderColor: theme.border }}>
      {items.map((item, i) => (
        <div key={i} className="flex-1 min-w-[80px] flex flex-col items-center justify-center py-4 md:py-6 text-center border-r last:border-r-0" style={{ borderColor: theme.border }}>
          <span className="text-sm md:text-xl font-black" style={{ color: theme.text }}>{item.value}</span>
          <span className="text-[8px] md:text-[10px] mt-0.5 font-bold uppercase tracking-widest" style={{ color: theme.muted }}>{item.label}</span>
        </div>
      ))}
    </div>
  );
}

function ProbadorProducts({ products, primaryColor, secondaryColor, ctaText, onProductClick, selectedId }: { products: ProductData[]; primaryColor: string; secondaryColor?: string; ctaText?: string | null; onProductClick: (id: string) => void; selectedId: string | null }) {
  const theme = useContrastTheme('#f9fafb');
  if (!products || !products.length) return null;
  const accentColor = secondaryColor || primaryColor;

  return (
    <section id="probador-products" className="py-16 px-4 md:px-6" style={{ backgroundColor: theme.bg }}>
      <div className="max-w-5xl mx-auto text-center">
        <p className="text-[9px] font-black uppercase tracking-[0.3em] mb-3" style={{ color: accentColor }}>Catálogo Curado</p>
        <h2 className="text-2xl md:text-5xl font-black mb-12 tracking-tighter italic uppercase leading-none" style={{ color: theme.text }}>Nuestros productos</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
          {products.map(p => (
            <button key={p.id} onClick={() => onProductClick(p.id)}
              className="text-left group relative rounded-3xl overflow-hidden border transition-all duration-300 hover:shadow-2xl"
              style={{ backgroundColor: '#ffffff', borderColor: selectedId === p.id ? primaryColor : '#e5e7eb', borderWidth: selectedId === p.id ? 2 : 1 }}>
              <div className="relative aspect-square overflow-hidden" style={{ backgroundColor: theme.surface }}>
                <ProductImage src={p.image_url} alt={p.name} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" />
                {p.badge && <div className="absolute top-3 left-3 scale-90 origin-top-left"><ProductBadge badge={p.badge} /></div>}
                <div className={`absolute inset-0 flex items-center justify-center transition-opacity ${selectedId === p.id ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`} style={{ backgroundColor: 'rgba(0,0,0,0.2)' }}>
                   <div className="px-4 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest shadow-xl" style={{ backgroundColor: '#ffffff', color: '#000000' }}>
                      {selectedId === p.id ? 'Seleccionado' : (ctaText || 'Probar')}
                    </div>
                 </div>
              </div>
              <div className="p-5">
                <p className="text-[9px] font-bold uppercase tracking-widest mb-1" style={{ color: theme.muted }}>{p.category}</p>
                <h3 className="text-sm font-black uppercase tracking-tight line-clamp-1 transition-colors" style={{ color: theme.text }}>{p.name}</h3>
                {p.price != null && <p className="text-base font-black mt-2" style={{ color: theme.text }}>${p.price.toLocaleString('es-CO')}</p>}
              </div>
            </button>
          ))}
        </div>
      </div>
    </section>
  );
}

function ProbadorInfo({ brand, secondaryColor }: { brand: BrandData; secondaryColor?: string }) {
  const DAYS_ORDER = ['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado', 'Domingo'];
  let scheduleEntries: [string, string][] = [];
  try {
    const rawSchedule = brand.schedule ?? {};
    if (rawSchedule && typeof rawSchedule === 'object') {
      scheduleEntries = DAYS_ORDER
        .filter(day => rawSchedule[day] || rawSchedule[day.toLowerCase()])
        .map(day => [day, (rawSchedule[day] || rawSchedule[day.toLowerCase()]) as string]);
    }
  } catch (e) { console.error(e); }

  const theme = useContrastTheme('#ffffff');
  const accentColor = secondaryColor || '#FF5C3A';
  if (scheduleEntries.length === 0 && !brand.city_display) return null;

  return (
    <section className="py-16 px-6 border-t" style={{ backgroundColor: theme.bg, borderColor: theme.border }}>
      <div className="max-w-4xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-12 md:gap-20">
        {brand.city_display && (
          <div className="space-y-4">
            <span className="text-[9px] font-black uppercase tracking-[0.3em]" style={{ color: accentColor }}>Encuéntranos</span>
            <h3 className="text-2xl font-black uppercase italic tracking-tight" style={{ color: theme.text }}>{brand.city_display}</h3>
            {brand.national_shipping && (
              <div className="flex items-center gap-2 px-4 py-2 rounded-xl w-fit" style={{ backgroundColor: '#ecfdf5', color: '#059669' }}>
                <span className="w-1.5 h-1.5 rounded-full animate-pulse" style={{ backgroundColor: '#10b981' }} />
                <span className="text-[10px] font-black uppercase tracking-widest">Envíos Nacionales Activos</span>
              </div>
            )}
          </div>
        )}
        {scheduleEntries.length > 0 && (
          <div className="space-y-6">
            <span className="text-[9px] font-black uppercase tracking-[0.3em]" style={{ color: accentColor }}>Horarios</span>
            <div className="grid grid-cols-1 gap-2">
              {scheduleEntries.map(([day, hours]) => (
                <div key={day} className="flex justify-between items-center py-2 border-b last:border-0" style={{ borderColor: theme.border }}>
                  <span className="text-[10px] font-bold uppercase" style={{ color: theme.muted }}>{day}</span>
                  <span className={`text-[11px] font-black tracking-tight ${hours.toLowerCase().includes('cerrado') ? 'italic' : ''}`} style={{ color: hours.toLowerCase().includes('cerrado') ? '#f87171' : theme.text }}>{hours}</span>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </section>
  );
}

export function TemplateModerno({ brandSlug, brand, products, footerUrl, isPreview = false }: { brandSlug: string; brand: BrandData; products: ProductData[]; footerUrl?: string; isPreview?: boolean }) {
  const primary = brand.social_links?._landing_primary || brand.primary_color || '#111111';
  const secondary = brand.social_links?._landing_secondary || primary;
  const [selectedId, setSelectedId] = useState<string | null>(products && products.length > 0 ? products[0].id : null);

  const scrollToTryOn = () => {
    const el = document.getElementById('probador-tryon');
    if (el) el.scrollIntoView({ behavior: 'smooth', block: 'center' });
  };

  const handleProductClick = (id: string) => {
    setSelectedId(id);
    scrollToTryOn();
  };

  return (
    <div className={`min-h-screen flex flex-col bg-white ${brand.landing_font || 'font-jakarta'} overflow-x-hidden ${isPreview ? 'p-0 h-auto' : ''}`} style={{ "--primary": primary, "--secondary": secondary, "--secondary-10": secondary + "1a", "--secondary-20": secondary + "33", "--secondary-05": secondary + "0d" } as React.CSSProperties}>
      <ProbadorNav brand={brand} />
      <ProbadorHero brand={brand} onScrollDown={() => document.getElementById('probador-products')?.scrollIntoView({ behavior: 'smooth' })} isPreview={isPreview} />
      <ProbadorTrustBar brand={brand} />
      <ProbadorProducts products={products} primaryColor={primary} secondaryColor={secondary} ctaText={brand.cta_button_text} onProductClick={handleProductClick} selectedId={selectedId} />
      
      <section id="probador-tryon" className="py-16 px-4 md:px-6" style={{ backgroundColor: brand.widget_bg_color || '#0a0a0a' }}>
        <div className="max-w-2xl mx-auto">
          <div className="text-center mb-10 space-y-3">
            <span className="text-[9px] font-black uppercase tracking-[0.4em] text-[var(--secondary)]">Motor IA</span>
            <h2 className="text-3xl md:text-5xl font-black text-white tracking-tighter uppercase italic leading-none">Probador Virtual</h2>
            <p className="text-gray-500 text-xs md:text-sm font-medium">Sube tu foto y procesa el producto seleccionado con IA</p>
          </div>
          <div className={isPreview ? "overflow-hidden" : "rounded-[2.5rem] overflow-hidden shadow-2xl shadow-black/50 border border-white/5"}>
            <TryOnWidget brandSlug={brandSlug} isEmbed={true} initialProductId={selectedId} forceLayout="bare" lockProductSelection={true} />
          </div>
        </div>
      </section>

      <ProbadorInfo brand={brand} secondaryColor={secondary} />

      <footer className="py-16 px-6 text-center border-t border-gray-50 bg-white mt-auto">
        <p className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] text-gray-300">
          Powered by <a href={footerUrl || 'https://lookitry.com'} target="_blank" rel="noopener noreferrer" className="font-bold hover:opacity-80 transition-all text-gray-900">Look<span className="text-[#FF5C3A]">itry</span> IA</a>
        </p>
      </footer>

      {brand.whatsapp_contact && !isPreview && <WhatsAppFAB phone={brand.whatsapp_contact} message={brand.whatsapp_message} />}
    </div>
  );
}
